// QR Code images (base64)
(function(){
  var a="data:image/png;base64,";
  var w="data:image/png;base64,";
  function inject(){
    var ai=document.getElementById('qr-img-alipay');
    var wi=document.getElementById('qr-img-wechat');
    if(ai) ai.src=a;
    if(wi) wi.src=w;
  }
  if(document.readyState==='loading') document.addEventListener('DOMContentLoaded',inject);
  else inject();
})();
